/**
 * Clawzd — App Builder Panel.
 *
 * UI for browsing, creating, previewing, and managing mini-apps
 * generated by the LLM via the App Builder API.
 *
 * Uses window globals: ICONS (from icons.js)
 *
 * API:
 *   POST   /apps              — Create from template
 *   GET    /apps              — List all apps
 *   GET    /apps/{id}/meta    — App metadata
 *   GET    /apps/{id}/preview — Live preview
 *   PUT    /apps/{id}         — Update files
 *   DELETE /apps/{id}         — Delete
 *   GET    /apps/templates    — Available templates
 */

const AppBuilderPanel = (() => {
  let _apps = [];
  let _templates = {};

  // 40 curated emojis for the app icon picker
  const _EMOJIS = [
    '📦', '🎨', '🎵', '🎬', '🎲', '🏆', '💡', '⛑️', '🔒', '📋', '📅', '📞', '📐', '🌍', '💰', '💎', '🔥', '⚡', '🌟', '🛡️', '🔮', '🧩', '🤖', '👾', '🎮', '🚘', '🚁', '☢️', '🧪', '🎯',
    '🦊', '🐉', '🦄', '🍕', '☕', '🎸', '📊', '📈', '🔧', '⚙️', '🔬', '📝', '📚', '💬', '🔔', '🏠', '🛒', '🏛️', '🚀', '🍔', '📸', '⚓', '⌚'
  ];

  function _emojiOptions(selected) {
    return _EMOJIS.map(e =>
      `<option value="${e}" ${e === selected ? 'selected' : ''} style="font-size:20px;">${e}</option>`
    ).join('');
  }

  function init() {
    // No overlay creation needed anymore
  }

  async function open() {
    await Promise.all([_loadApps(), _loadTemplates()]);
    _renderList();
  }

  function close() {
    // Left for compatibility, but no-op since it's inside SkillCatalog
  }

  async function _loadApps() {
    try {
      const res = await fetch('/apps');
      _apps = await res.json();
    } catch (e) {
      _apps = [];
    }
  }

  async function _loadTemplates() {
    try {
      const res = await fetch('/apps/templates');
      _templates = await res.json();
    } catch (e) {
      _templates = {};
    }
  }

  function _renderList() {
    const body = document.getElementById('ab-body');
    if (!body) return;

    if (_apps.length === 0) {
      body.innerHTML = `
        <div class="ab-empty">
          <div class="ab-empty-icon">${ICONS.box(48)}</div>
          <p>No apps yet. Create your first mini-app!</p>
          <button class="ab-btn ab-btn-primary" onclick="AppBuilderPanel.showCreate()">${ICONS.plus(14)} Create App</button>
        </div>
      `;
      return;
    }

    body.innerHTML = `
      <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:16px;">
        <h3 style="margin:0; font-size:16px; display:flex; align-items:center; gap:6px;">${ICONS.box(16)} Your Apps</h3>
        <button class="ab-btn ab-btn-primary" onclick="AppBuilderPanel.showCreate()">${ICONS.plus(14)} Create App</button>
      </div>
      <div class="ab-grid">
        ${_apps.map(a => _renderAppCard(a)).join('')}
      </div>
    `;
  }

  function _renderAppCard(app) {
    const time = _timeAgo(app.updated_at || app.created_at);
    const fileCount = app.files ? app.files.length : 0;
    const escapedName = (app.name || 'Untitled').replace(/'/g, "\\'");

    // Check if visual is a color or URL, default to empty
    const visualStyle = app.visual ? `style="background: ${app.visual};"` : '';
    // Use app.icon (e.g. emoji) or fallback to monitor icon
    const iconContent = app.icon ? `<span style="font-size: 32px;">${app.icon}</span>` : ICONS.monitor(32);

    return `
      <div class="ab-card" data-id="${app.id}">
        <div class="ab-card-preview" ${visualStyle} onclick="AppBuilderPanel.preview('${app.id}')">
          <div class="ab-card-icon">${iconContent}</div>
        </div>
        <div class="ab-card-body">
          <div class="ab-card-name" style="display:flex; justify-content:space-between; align-items:center;">
            <span>${app.name || 'Untitled'}</span>
            <button class="ab-btn-sm" style="background:transparent; border:none; color:var(--text-muted); cursor:pointer; padding:0 4px;" onclick="AppBuilderPanel.showEdit('${app.id}')" title="Edit App Settings">${ICONS.penTool(12)}</button>
          </div>
          <div class="ab-card-meta">
            <span>v${app.version || 1}</span>
            <span>${fileCount} files</span>
            <span>${time}</span>
          </div>
        </div>
        <div class="ab-card-actions">
          <button class="ab-btn-edit" onclick="AppBuilderPanel.editInChat('${app.id}', '${escapedName}')" title="Edit in Chat">${ICONS.penTool(12)} Edit</button>
          <button class="ab-btn-sm" onclick="AppBuilderPanel.preview('${app.id}')" title="Preview">${ICONS.eye(14)}</button>
          <button class="ab-btn-sm ab-btn-danger" onclick="AppBuilderPanel.remove('${app.id}')" title="Delete">${ICONS.trash(14)}</button>
        </div>
      </div>
    `;
  }

  function showCreate() {
    const body = document.getElementById('ab-body');
    if (!body) return;

    body.innerHTML = `
      <div class="ab-create" style="max-width: 600px; margin: 0 auto; padding: 20px;">
        <button class="ab-btn-back" onclick="AppBuilderPanel.open()" style="margin-bottom: 20px;">${ICONS.chevronLeft(14)} Back</button>
        <h3 style="margin-bottom: 24px; font-size: 18px;">Application Creation Wizard</h3>
        
        <div style="display: flex; flex-direction: column; gap: 20px;">
          <!-- Basic Info -->
          <div style="display: flex; flex-direction: column; gap: 8px;">
            <label style="font-weight: 500; font-size: 14px;">1. Application Identity</label>
            <div style="display: flex; gap: 8px;">
              <input type="text" id="ab-app-name" class="ab-input" placeholder="App name..." value="My App" style="flex: 1;">
              <select id="ab-app-icon" class="ab-input" style="width: 90px; font-size: 20px; text-align: center;">
                ${_emojiOptions('📦')}
              </select>
              <input type="color" id="ab-app-visual" class="ab-input" value="#1e293b" title="App Theme Color" style="width: 50px; padding: 2px;">
            </div>
          </div>

          <!-- App Type Selection -->
          <div style="display: flex; flex-direction: column; gap: 8px;">
            <label style="font-weight: 500; font-size: 14px;">2. What type of application do you want to create?</label>
            <select id="ab-app-type" class="ab-input" onchange="AppBuilderPanel.toggleGameOptions()" style="width: 100%;">
              <option value="standard">Standard App (Dashboard / Tool)</option>
              <option value="blank">Blank App (Custom)</option>
              <option value="game">Mini-Game (Arcade / 2D)</option>
            </select>
          </div>

          <!-- Game Options (Hidden by default) -->
          <div id="ab-game-options" style="display: none; flex-direction: column; gap: 8px; padding-left: 16px; border-left: 2px solid var(--border-color);">
            <label style="font-weight: 500; font-size: 14px; color: var(--accent-color);">Choose your Game Model:</label>
            <select id="ab-game-model" class="ab-input" style="width: 100%;">
              <option value="space_invaders">Space Invaders</option>
              <option value="pacman">Pacman</option>
              <option value="arcade_combat">2D Arcade Combat Game</option>
            </select>
            <small style="color: var(--text-muted); margin-top: 4px;">
              * The game will be built fully functional in vanilla JavaScript and controlled using keyboard arrows and action buttons.
            </small>
          </div>

          <!-- Submit -->
          <button class="ab-btn ab-btn-primary" onclick="AppBuilderPanel.create()" style="margin-top: 16px; padding: 10px; font-weight: bold;">
            ${ICONS.bolt(14)} Generate Application
          </button>
        </div>
      </div>
    `;
  }

  function toggleGameOptions() {
    const typeSelect = document.getElementById('ab-app-type');
    const gameOptions = document.getElementById('ab-game-options');
    if (typeSelect && gameOptions) {
      if (typeSelect.value === 'game') {
        gameOptions.style.display = 'flex';
      } else {
        gameOptions.style.display = 'none';
      }
    }
  }

  async function create() {
    const nameEl = document.getElementById('ab-app-name');
    const iconEl = document.getElementById('ab-app-icon');
    const visualEl = document.getElementById('ab-app-visual');
    const typeSelect = document.getElementById('ab-app-type');
    const gameModelSelect = document.getElementById('ab-game-model');

    const name = nameEl?.value || 'My App';
    const icon = iconEl?.value || '📦';
    const visual = visualEl?.value || '#1e293b';
    const appType = typeSelect?.value || 'blank';

    // Determine the template key for the backend
    const templateKey = appType === 'standard' ? 'dashboard' : 'blank';

    // Construct custom prompt if it's a game
    let customPrompt = '';
    if (appType === 'game') {
      const gameModel = gameModelSelect?.value || 'space_invaders';
      const gameNames = {
        'space_invaders': 'Space Invaders',
        'pacman': 'Pacman',
        'arcade_combat': '2D Arcade Combat Game'
      };
      const modelName = gameNames[gameModel];

      customPrompt = `I want to create a new Mini-Game application named "${name}".\n\n` +
        `Please build a fully functional **${modelName}** game using vanilla HTML, CSS, and JavaScript. ` +
        `The game MUST be playable directly in the browser using the keyboard (arrow keys for movement, and action buttons like Space/Ctrl for actions if needed). ` +
        `Ensure the game has a start screen, a game over screen, score tracking, and smooth 2D animations using Canvas or DOM elements. ` +
        `Make it look visually appealing with modern CSS and use the theme color ${visual}.\n\n` +
        `Update the app code and provide a complete working implementation. ` +
        `Preview URL will be /apps/[AppID]/preview`;
    }

    try {
      const res = await fetch('/apps', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name, template: templateKey, icon, visual }),
      });
      const app = await res.json();
      if (typeof window.toast === 'function') {
        window.toast(`App "${name}" created! Redirecting to Chat...`, 'success');
      }
      await _loadApps();
      _renderList();

      // Inject the appId into the custom prompt if it exists
      if (customPrompt) {
        customPrompt = customPrompt.replace('[AppID]', app.id);
      }

      // Redirect to chat for AI-assisted editing
      editInChat(app.id, name, customPrompt);
    } catch (e) {
      if (typeof window.toast === 'function') {
        window.toast('Failed to create app', 'error');
      }
    }
  }

  /**
   * Close the Skill Catalog and send a pre-filled prompt to Chat
   * so the user can edit/update the app via the AI assistant.
   */
  function editInChat(appId, appName, customPrompt = '') {
    // Close the Skill Catalog overlay
    const overlay = document.getElementById('skills-catalog-overlay');
    if (overlay) overlay.classList.remove('open');

    // Pre-fill the chat input with an edit prompt
    const chatInput = document.getElementById('chat-input');
    if (chatInput) {
      chatInput.value = customPrompt || (`Edit my application "${appName}" (ID: ${appId}). ` +
        `Describe what features or changes you'd like to add, and I'll update the app code for you.\n\n` +
        `Preview: /apps/${appId}/preview`);
      chatInput.focus();
      // Trigger resize
      chatInput.style.height = 'auto';
      chatInput.style.height = Math.min(chatInput.scrollHeight, 150) + 'px';
    }

    // Switch to chat mode if in editor mode
    const chatModeBtn = document.querySelector('#mode-toggle .mode-btn[data-mode="chat"]');
    if (chatModeBtn && !chatModeBtn.classList.contains('active')) {
      chatModeBtn.click();
    }
  }

  function showEdit(appId) {
    const app = _apps.find(a => a.id === appId);
    if (!app) return;
    const body = document.getElementById('ab-body');
    if (!body) return;

    body.innerHTML = `
      <div class="ab-create">
        <button class="ab-btn-back" onclick="AppBuilderPanel.open()">${ICONS.chevronLeft(14)} Back</button>
        <h4>Edit Application Settings</h4>
        <div style="display: flex; gap: 8px; margin-bottom: 12px;">
          <input type="text" id="ab-app-name" class="ab-input" placeholder="App name..." value="${(app.name || '').replace(/"/g, '&quot;')}" style="flex: 1;">
          <select id="ab-app-icon" class="ab-input" style="width: 90px; font-size: 20px; text-align: center;">
            ${_emojiOptions(app.icon || '📦')}
          </select>
          <input type="color" id="ab-app-visual" class="ab-input" value="${app.visual || '#1e293b'}" title="App Theme Color" style="width: 50px; padding: 2px;">
        </div>
        <button class="ab-btn ab-btn-primary" onclick="AppBuilderPanel.saveEdit('${app.id}')">Save Changes</button>
      </div>
    `;
  }

  async function saveEdit(appId) {
    const nameEl = document.getElementById('ab-app-name');
    const iconEl = document.getElementById('ab-app-icon');
    const visualEl = document.getElementById('ab-app-visual');
    const name = nameEl?.value || 'My App';
    const icon = iconEl?.value || '📦';
    const visual = visualEl?.value || '#1e293b';

    try {
      await fetch(`/apps/${appId}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: name.trim(), icon, visual }),
      });
      await _loadApps();
      _renderList();
      if (typeof window.toast === 'function') {
        window.toast('App updated successfully', 'success');
      }
    } catch (e) {
      if (typeof window.toast === 'function') window.toast('Failed to update app', 'error');
    }
  }

  function preview(appId) {
    window.open(`/apps/${appId}/preview`, '_blank', 'width=800,height=600');
  }

  async function remove(appId) {
    if (!confirm('Delete this app?')) return;
    try {
      await fetch(`/apps/${appId}`, { method: 'DELETE' });
      await _loadApps();
      _renderList();
      if (typeof window.toast === 'function') {
        window.toast('App deleted', 'info');
      }
    } catch (e) {
      console.warn('Delete failed', e);
    }
  }

  function _timeAgo(iso) {
    if (!iso) return '';
    const d = (Date.now() - new Date(iso).getTime()) / 1000;
    if (d < 60) return 'just now';
    if (d < 3600) return Math.floor(d / 60) + 'm ago';
    if (d < 86400) return Math.floor(d / 3600) + 'h ago';
    return Math.floor(d / 86400) + 'd ago';
  }

  return { init, open, close, showCreate, create, toggleGameOptions, preview, remove, editInChat, showEdit, saveEdit };
})();

window.AppBuilderPanel = AppBuilderPanel;
